    "previewCode": "<!DOCTYPE html><html><head><style>\n*{margin:0;padding:0;box-sizing:border-box}body{font-family:ui-sans-serif,system-ui;background:#07080c;min-height:100vh;display:flex;flex-direction:column}main{flex:1;display:flex;align-items:center;justify-content:center;opacity:.2}footer{width:min(1100px,92vw);margin:0 auto 28px;padding:34px 28px 20px;position:relative;border-radius:22px;overflow:hidden;border:1px solid rgba(255,255,255,.10);background:linear-gradient(180deg,rgba(124,92,252,.12),rgba(34,211,238,.06));color:#eaf2ff}\n.waves{position:absolute;left:-10%;right:-10%;top:-38px;height:130px;filter:blur(0px);opacity:.95;pointer-events:none}\n.wave{position:absolute;inset:0;background-repeat:repeat;transform-origin:center;animation:drift 7s ease-in-out infinite}@keyframes drift{0%,100%{transform:translateX(-4%) translateY(0) }50%{transform:translateX(4%) translateY(6px)}}\n.wave1{background-image:radial-gradient(circle at 20% 30%,rgba(124,92,252,.55),transparent 55%),radial-gradient(circle at 60% 60%,rgba(34,211,238,.35),transparent 60%);mask:linear-gradient(#000,transparent)}\n.wave2{background-image:radial-gradient(circle at 30% 40%,rgba(34,211,238,.45),transparent 58%),radial-gradient(circle at 80% 30%,rgba(124,92,252,.30),transparent 62%);animation-duration:9s;opacity:.75}\n.grid{position:relative;display:grid;grid-template-columns:1.3fr 1fr 1fr;gap:26px}\n@media (max-width:860px){.grid{grid-template-columns:1fr 1fr}}.brand h3{font-size:16px;letter-spacing:-.02em}.brand p{color:rgba(234,242,255,.72);font-size:13px;line-height:1.6;margin-top:8px;max-width:420px}\nh4{font-size:11px;letter-spacing:.16em;text-transform:uppercase;color:rgba(234,242,255,.6);margin-bottom:12px}\na{display:block;color:rgba(234,242,255,.72);text-decoration:none;font-size:13px;line-height:1.8;position:relative;padding-left:14px;transition:color .2s, transform .25s}\na::before{content:'';position:absolute;left:0;top:50%;width:6px;height:1px;background:linear-gradient(90deg,#22d3ee,#7c5cf6);transform:translateY(-50%);opacity:.0;transition:opacity .2s}\na:hover{color:#fff;transform:translateX(4px)}a:hover::before{opacity:.9}\n.bottom{position:relative;margin-top:20px;padding-top:16px;border-top:1px solid rgba(255,255,255,.10);display:flex;justify-content:space-between;gap:10px;font-size:12px;color:rgba(234,242,255,.6)}\n</style></head><body><main>Preview Area</main><footer><div class='waves'><div class='wave wave1'></div><div class='wave wave2'></div></div><div class='grid'><div class='brand'><h3>Liquid<span style='color:#7c5cf6'>Wave</span> Footer</h3><p>Animated liquid gradient waves behind your navigation links for a modern, motion-friendly aesthetic.</p></div><div class='col'><h4>Product</h4><a href='#'>Overview</a><a href='#'>Templates</a><a href='#'>Changelog</a></div><div class='col'><h4>Resources</h4><a href='#'>Docs</a><a href='#'>Blog</a><a href='#'>Support</a></div></div><div class='bottom'><span>© 2026 Animation AI</span><span>Crafted with waves</span></div></footer></body></html>",
    "code": "'use client'\nimport React from 'react'\n\nconst LinkCol = ({ title, links }: { title: string; links: string[] }) => (\n  <div>\n    <h4 className=\"text-[11px] uppercase tracking-[.16em] text-white/60 mb-3\">{title}</h4>\n    <div className=\"flex flex-col gap-1.5\">\n      {links.map((l) => (\n        <a\n          key={l}\n          href=\"#\"\n          className=\"text-sm text-white/70 hover:text-white transition-colors\n            pl-4 relative py-1 group\"\n        >\n          <span className=\"absolute left-0 top-1/2 -translate-y-1/2 w-1.5 h-px bg-gradient-to-r from-cyan-300 to-violet-500\n            opacity-0 group-hover:opacity-90 transition-opacity\" />\n          {l}\n        </a>\n      ))}\n    </div>\n  </div>\n)\n\nexport default function LiquidWaveFooter() {\n  return (\n    <footer\n      className=\"relative overflow-hidden rounded-2xl border border-white/10\n        bg-gradient-to-b from-[#7c5cf6]/15 to-cyan-400/5\n        px-7 py-8\"\n    >\n      <div className=\"absolute left-[-10%] right-[-10%] top-[-38px] h-[130px] pointer-events-none\">\n        <div\n          className=\"absolute inset-0 animate-[drift_7s_ease-in-out_infinite]\"\n          style={{\n            backgroundImage:\n              'radial-gradient(circle at 20% 30%, rgba(124,92,252,.55), transparent 55%), radial-gradient(circle at 60% 60%, rgba(34,211,238,.35), transparent 60%)',\n            maskImage: 'linear-gradient(#000, transparent)',\n          }}\n        />\n        <div\n          className=\"absolute inset-0 animate-[drift_9s_ease-in-out_infinite] opacity-75\"\n          style={{\n            backgroundImage:\n              'radial-gradient(circle at 30% 40%, rgba(34,211,238,.45), transparent 58%), radial-gradient(circle at 80% 30%, rgba(124,92,252,.30), transparent 62%)',\n            maskImage: 'linear-gradient(#000, transparent)',\n          }}\n        />\n      </div>\n\n      <style jsx>{`@keyframes drift{0%,100%{transform:translateX(-4%) translateY(0)}50%{transform:translateX(4%) translateY(6px)}}`}</style>\n\n      <div className=\"relative grid grid-cols-1 md:grid-cols-3 gap-7\">\n        <div className=\"md:col-span-1\">\n          <h3 className=\"text-base sm:text-lg font-semibold tracking-tight\">\n            Liquid<span className=\"text-violet-400\">Wave</span> Footer\n          </h3>\n          <p className=\"mt-3 text-sm text-white/70 leading-relaxed max-w-[420px]\">\n            Animated liquid gradient waves behind your navigation links for a\n            modern, motion-friendly aesthetic.\n          </p>\n        </div>\n\n        <div className=\"md:col-span-1\">\n          <LinkCol title=\"Product\" links={[\"Overview\", \"Templates\", \"Changelog\"]} />\n        </div>\n\n        <div className=\"md:col-span-1\">\n          <LinkCol title=\"Resources\" links={[\"Docs\", \"Blog\", \"Support\"]} />\n        </div>\n      </div>\n\n      <div className=\"relative mt-6 pt-4 border-t border-white/10 flex items-center justify-between gap-3 text-xs text-white/60\">\n        <span>© {new Date().getFullYear()} Animation AI</span>\n        <span>Crafted with waves</span>\n      </div>\n    </footer>\n  )\n}\n",
