    "previewCode": "<!DOCTYPE html><html><head><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:ui-sans-serif,system-ui;background:#07080c;min-height:100vh;display:flex;flex-direction:column}main{flex:1;display:flex;align-items:center;justify-content:center;opacity:.2}footer{width:min(920px,92vw);margin:0 auto 28px;border-radius:18px;border:1px solid rgba(255,255,255,.10);background:rgba(255,255,255,.03);padding:22px 18px 14px;color:#eaf2ff;position:relative;overflow:hidden}.frame{position:absolute;inset:-50px -80px auto auto;width:260px;height:160px;background:radial-gradient(circle at 20% 20%,rgba(124,92,252,.35),transparent 60%);pointer-events:none}h3{font-size:14px;font-weight:800;letter-spacing:-.02em}p{margin-top:8px;color:rgba(234,242,255,.68);font-size:13px;line-height:1.6}.stack{margin-top:14px;display:flex;flex-direction:column;gap:10px}.row{border-top:1px solid rgba(255,255,255,.10);padding-top:10px;display:flex;gap:14px;align-items:flex-start;justify-content:space-between}.row:first-child{border-top:0}.label{font-size:11px;text-transform:uppercase;letter-spacing:.16em;color:rgba(234,242,255,.55)}.links{display:flex;flex-direction:column;gap:6px}.links a{color:rgba(234,242,255,.70);text-decoration:none;font-size:13px;position:relative;padding-left:12px;transition:transform .2s,color .2s} .links a:before{content:'';position:absolute;left:0;top:50%;width:0;height:1px;background:linear-gradient(90deg,#22d3ee,#7c5cf6);transform:translateY(-50%);opacity:.0;transition:width .25s, opacity .2s} .links a:hover{color:#fff;transform:translateX(3px)} .links a:hover:before{width:10px;opacity:.9} .bottom{margin-top:14px;padding-top:12px;border-top:1px solid rgba(255,255,255,.10);display:flex;justify-content:space-between;gap:10px;font-size:12px;color:rgba(234,242,255,.6)}.micro{position:absolute;left:20px;bottom:-40px;width:240px;height:240px;background:radial-gradient(circle,rgba(34,211,238,.15),transparent 60%);filter:blur(0);animation:pop 4.5s ease-in-out infinite;pointer-events:none}@keyframes pop{0%,100%{transform:translateY(0);opacity:.35}50%{transform:translateY(-12px);opacity:.6}}@media(max-width:520px){.row{flex-direction:column;gap:8px}}</style></head><body><main>Preview Area</main><footer><div class='frame'></div><div class='micro'></div><h3>Minimal Stack</h3><p>Small stacked sections with dividers and hover-reveal underline markers.</p><div class='stack'><div class='row'><div class='label'>Product</div><div class='links'><a href='#'>Templates</a><a href='#'>Layouts</a><a href='#'>Components</a></div></div><div class='row'><div class='label'>Resources</div><div class='links'><a href='#'>Docs</a><a href='#'>Blog</a><a href='#'>Support</a></div></div><div class='row'><div class='label'>Company</div><div class='links'><a href='#'>About</a><a href='#'>Careers</a><a href='#'>Privacy</a></div></div></div><div class='bottom'><span>© 2026 Animation AI</span><span>Designed to stay out of the way</span></div></footer></body></html>",
    "code": "'use client'\nimport React from 'react'\n\nfunction StackRow({ label, links }: { label: string; links: string[] }) {\n  return (\n    <div className=\"border-t border-white/10 pt-3 flex gap-4 items-start justify-between\">\n      <div className=\"text-[11px] uppercase tracking-[.16em] text-white/55\">{label}</div>\n      <div className=\"flex flex-col gap-1\">\n        {links.map((l) => (\n          <a\n            key={l}\n            href=\"#\"\n            className=\"relative text-sm text-white/70 hover:text-white transition-colors\n              pl-3 py-1\"\n          >\n            <span\n              aria-hidden\n              className=\"absolute left-0 top-1/2 -translate-y-1/2 h-px w-0 opacity-0\n                bg-gradient-to-r from-cyan-300 to-violet-500\n                transition-[width,opacity] duration-300 group-hover:w-2.5 group-hover:opacity-90\"\n            />\n            <span className=\"group block\">{l}</span>\n          </a>\n        ))}\n      </div>\n    </div>\n  )\n}\n\nexport default function MinimalStackFooter() {\n  return (\n    <footer\n      className=\"relative overflow-hidden rounded-2xl border border-white/10 bg-white/3\n        px-5 py-5\"\n    >\n      <div className=\"absolute -top-14 -right-20 w-72 h-44 bg-[radial-gradient(circle_at_20%_20%,rgba(124,92,252,.35),transparent_60%)] pointer-events-none\" />\n      <div className=\"absolute left-5 bottom-[-40px] w-60 h-60 bg-[radial-gradient(circle,rgba(34,211,238,.15),transparent_60%)]\n        animate-[pop_4.5s_ease-in-out_infinite] pointer-events-none\" />\n\n      <style jsx>{`@keyframes pop{0%,100%{transform:translateY(0);opacity:.35}50%{transform:translateY(-12px);opacity:.6}}`}</style>\n\n      <h3 className=\"text-sm sm:text-[14px] font-extrabold tracking-tight\">Minimal Stack</h3>\n      <p className=\"mt-2 text-sm text-white/70 leading-relaxed\">Small stacked sections with dividers and hover-reveal underline markers.</p>\n\n      <div className=\"mt-4 flex flex-col gap-2\">\n        <StackRow label=\"Product\" links={[\"Templates\", \"Layouts\", \"Components\"]} />\n        <StackRow label=\"Resources\" links={[\"Docs\", \"Blog\", \"Support\"]} />\n        <StackRow label=\"Company\" links={[\"About\", \"Careers\", \"Privacy\"]} />\n      </div>\n\n      <div className=\"mt-4 pt-3 border-t border-white/10 flex items-center justify-between gap-3 text-xs text-white/60\">\n        <span>© {new Date().getFullYear()} Animation AI</span>\n        <span>Designed to stay out of the way</span>\n      </div>\n    </footer>\n  )\n}\n",
    "prompt": "Minimal stacked footer:\n- Single container with subtle frosted border\n- 3 stacked rows with divider lines, label on left, links on right\n- Link hover: shift right + underline marker grows\n- Decorative corner glow + slight animated pulse\n- Bottom bar with top border and small text",

