    "description": "Bento-style footer grid where sections expand like an accordion with smooth height transitions.",
    "previewCode": "<!DOCTYPE html><html><head><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:ui-sans-serif,system-ui;background:#05060a;min-height:100vh;display:flex;flex-direction:column}main{flex:1;display:flex;align-items:center;justify-content:center;opacity:.2}footer{width:min(1100px,92vw);margin:0 auto 28px;border-radius:22px;border:1px solid rgba(255,255,255,.10);background:rgba(255,255,255,.03);overflow:hidden;color:#eaf2ff;position:relative}footer:before{content:'';position:absolute;inset:-120px auto auto -120px;width:420px;height:320px;background:radial-gradient(circle at 30% 30%,rgba(124,92,252,.35),transparent 60%);pointer-events:none}.grid{display:grid;grid-template-columns:1fr 1fr 1fr 1fr;gap:14px;padding:18px}.tile{background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.10);border-radius:18px;padding:14px;overflow:hidden}.tile button{width:100%;background:transparent;border:0;color:#eaf2ff;text-align:left;display:flex;align-items:center;justify-content:space-between;gap:10px;cursor:pointer}.tTitle{text-transform:uppercase;letter-spacing:.14em;font-size:11px;color:rgba(234,242,255,.65);font-weight:700}.chev{width:26px;height:26px;border-radius:12px;border:1px solid rgba(255,255,255,.14);display:flex;align-items:center;justify-content:center;transition:transform .25s;opacity:.9}.tile[data-open='true'] .chev{transform:rotate(180deg)}.body{max-height:0;opacity:0;transform:translateY(-6px);transition:max-height .35s ease,opacity .25s ease,transform .35s ease;overflow:hidden}.tile[data-open='true'] .body{max-height:180px;opacity:1;transform:translateY(0)}.links{display:flex;flex-direction:column;gap:8px;margin-top:12px}.links a{color:rgba(234,242,255,.72);text-decoration:none;font-size:13px;position:relative;padding-left:12px}.links a:before{content:'';position:absolute;left:0;top:50%;width:6px;height:1px;background:linear-gradient(90deg,#22d3ee,#7c5cf6);transform:translateY(-50%);opacity:.0;transition:opacity .2s}a:hover{color:#fff} a:hover:before{opacity:.9}.bottom{padding:14px 18px;border-top:1px solid rgba(255,255,255,.10);display:flex;justify-content:space-between;gap:10px;font-size:12px;color:rgba(234,242,255,.6)}@media(max-width:980px){.grid{grid-template-columns:1fr 1fr}}@media(max-width:560px){.grid{grid-template-columns:1fr 1fr}footer{border-radius:18px}}@media(max-width:420px){.grid{grid-template-columns:1fr}}</style></head><body><main>Preview Area</main><footer><div class='grid'><div class='tile' data-open='true'><button type='button'><span class='tTitle'>Product</span><span class='chev'>⌄</span></button><div class='body'><div class='links'><a href='#'>Templates</a><a href='#'>Navbars</a><a href='#'>Footers</a></div></div></div><div class='tile' data-open='false'><button type='button'><span class='tTitle'>Resources</span><span class='chev'>⌄</span></button><div class='body'><div class='links'><a href='#'>Docs</a><a href='#'>Blog</a><a href='#'>Changelog</a></div></div></div><div class='tile' data-open='false'><button type='button'><span class='tTitle'>Company</span><span class='chev'>⌄</span></button><div class='body'><div class='links'><a href='#'>About</a><a href='#'>Careers</a><a href='#'>Privacy</a></div></div></div><div class='tile' data-open='false'><button type='button'><span class='tTitle'>Community</span><span class='chev'>⌄</span></button><div class='body'><div class='links'><a href='#'>Discord</a><a href='#'>Events</a><a href='#'>Meetups</a></div></div></div></div><div class='bottom'><span>© 2026 Animation AI</span><span>Accordion bento footer</span></div><script>document.querySelectorAll('.tile button').forEach(btn=>{btn.addEventListener('click',()=>{const tile=btn.closest('.tile');const isOpen=tile.getAttribute('data-open')==='true';tile.setAttribute('data-open',isOpen?'false':'true')})})</script></footer></body></html>",
    "code": "'use client'\nimport React, { useState } from 'react'\n\nconst tiles = [\n  {\n    title: 'Product',\n    links: ['Templates', 'Navbars', 'Footers'],\n  },\n  {\n    title: 'Resources',\n    links: ['Docs', 'Blog', 'Changelog'],\n  },\n  {\n    title: 'Company',\n    links: ['About', 'Careers', 'Privacy'],\n  },\n  {\n    title: 'Community',\n    links: ['Discord', 'Events', 'Meetups'],\n  },\n] as const\n\nexport default function AccordionBentoFooter() {\n  const [open, setOpen] = useState<string>(tiles[0].title)\n\n  return (\n    <footer\n      className=\"relative overflow-hidden rounded-2xl border border-white/10 bg-white/3\n        px-4\"\n    >\n      <div className=\"absolute -top-28 -left-28 w-[420px] h-[320px]\n        bg-[radial-gradient(circle_at_30%_30%,rgba(124,92,252,.35),transparent_60%)] pointer-events-none\" />\n\n      <div className=\"grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3 p-4\">\n        {tiles.map((t) => {\n          const isOpen = open === t.title\n          return (\n            <div\n              key={t.title}\n              className=\"bg-white/5 border border-white/10 rounded-2xl p-4 overflow-hidden\"\n              data-open={isOpen}\n            >\n              <button\n                type=\"button\"\n                onClick={() => setOpen(isOpen ? '' : t.title)}\n                className=\"w-full flex items-center justify-between gap-3\"\n              >\n                <span className=\"text-[11px] uppercase tracking-[.14em] text-white/65 font-bold\">\n                  {t.title}\n                </span>\n                <span\n                  className=\"w-7 h-7 rounded-xl border border-white/15 flex items-center justify-center text-white/70\n                    transition-transform duration-300\"\n                  style={{ transform: isOpen ? 'rotate(180deg)' : 'rotate(0deg)' }}\n                >\n                  ⌄\n                </span>\n              </button>\n\n              <div\n                className=\"transition-all duration-300 overflow-hidden\"\n                style={{\n                  maxHeight: isOpen ? 180 : 0,\n                  opacity: isOpen ? 1 : 0,\n                  transform: isOpen ? 'translateY(0px)' : 'translateY(-6px)',\n                }}\n              >\n                <div className=\"mt-3 flex flex-col gap-2\">\n                  {t.links.map((l) => (\n                    <a\n                      key={l}\n                      href=\"#\"\n                      className=\"text-sm text-white/70 hover:text-white transition-colors relative pl-3 py-1\"\n                    >\n                      <span\n                        aria-hidden\n                        className=\"absolute left-0 top-1/2 -translate-y-1/2 w-1.5 h-px\n                          bg-gradient-to-r from-cyan-300 to-violet-500 opacity-0 hover:opacity-100\"\n                      />\n                      {l}\n                    </a>\n                  ))}\n                </div>\n              </div>\n            </div>\n          )\n        })}\n      </div>\n\n      <div className=\"px-4 py-3 border-t border-white/10 flex items-center justify-between gap-3 text-xs text-white/60\">\n        <span>© {new Date().getFullYear()} Animation AI</span>\n        <span>Accordion bento footer</span>\n      </div>\n    </footer>\n  )\n}\n",
    "prompt": "Accordion bento footer:\n- Bento grid tiles (4 sections) with rounded cards and thin borders\n- Each tile expands/collapses with smooth max-height/opacity/translate transitions\n- Tile header: uppercase label + chevron rotates when open\n- Links with small left underline marker on hover\n- Decorative corner radial glow + bottom bar",

